#!/bin/bash
set -e

# Week Two final challenge: create a valid raw transaction that uses an
# RBF/CSV-style low sequence number and spends the provided secondary UTXO.
SECONDARY_TX=""
TIMELOCK_ADDRESS="bcrt1qxhy8dnae50nwkg6xfmjtedgs6augk5edj2tm3e"
TIMELOCK_FEE=1000

SECONDARY_DECODED=$(bitcoin-cli -regtest decoderawtransaction "$SECONDARY_TX")
SECONDARY_TXID=$(echo "$SECONDARY_DECODED" | jq -r '.txid')
SECONDARY_OUTPUT_VALUE=$(echo "$SECONDARY_DECODED" | jq '.vout[1].value * 100000000 | floor')
TIMELOCK_AMOUNT=$((SECONDARY_OUTPUT_VALUE - TIMELOCK_FEE))
TIMELOCK_BTC=$(awk "BEGIN { printf \"%.8f\", $TIMELOCK_AMOUNT / 100000000 }")

TIMELOCK_INPUTS='[{"txid":"'$SECONDARY_TXID'","vout":1,"sequence":10}]'
TIMELOCK_OUTPUTS='{"'$TIMELOCK_ADDRESS'":'$TIMELOCK_BTC'}'

bitcoin-cli -regtest -named createrawtransaction inputs="$TIMELOCK_INPUTS" outputs="$TIMELOCK_OUTPUTS"